class Solution:
    def removeNodes(self, root, toRemove):
        if root is None:
            return None
        root.left = self.removeNodes(root.left, toRemove)
        root.right = self.removeNodes(root.right, toRemove)
        if root.val in toRemove:
            return None
        return root

